VALUES
  ('dietitian-moex-09744', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '動物細胞無法進行乙醛酸循環（the glyoxylate cycle），因此不能夠：', '["利用醣類合成脂肪", "利用脂肪合成醣類", "利用胺基酸碳骨架合成醣類", "以上皆非"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a5e1ee9083b2", "answer_pdf_sha1": "d1518fd8ddee", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09745', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '泛素（Ubiquitin）是一種：', '["細胞膜上的訊號接受器", "蛋白質標籤附著在要被降解的蛋白質分子上", "電子傳遞者", "蛋白質激化酶"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a5e1ee9083b2", "answer_pdf_sha1": "d1518fd8ddee", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09746', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '奇數碳脂肪酸降解後之產物可以進入檸檬酸循環，此種產物除了乙醯基輔酶A尚有：', '["α酮戊二酸（α-ketoglutarate）", "檸檬酸（citrate）", "丁酮二酸（oxaloacetate）", "琥珀酸基輔酶A（succinyl-CoA）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a5e1ee9083b2", "answer_pdf_sha1": "d1518fd8ddee", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09747', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '丙酮酸去氫酶複合體（Pyruvate dehydrogenase complex）催化丙酮酸轉變成乙醯基輔酶A（acetyl CoA） 的反應，除輔酶A、NADH、FAD、TPP外，還需用到輔酶：', '["硫脂酸（lipoic acid）", "生物素（biotin）", "磷酸吡哆醛（pyridoxal phosphate）", "四氫葉酸（tetrahydrofolic acid）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a5e1ee9083b2", "answer_pdf_sha1": "d1518fd8ddee", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09748', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '合成尿素（urea）直接參與反應的兩個氮原子來自：', '["銨離子和天門冬胺酸（aspartic acid）", "胺甲醯磷酸鹽（carbamoyl phosphate）和天門冬胺酸", "胺甲醯磷酸鹽和麩胺酸（glutamic acid）", "銨離子和麩胺酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a5e1ee9083b2", "answer_pdf_sha1": "d1518fd8ddee", "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
